export type ContractFieldType = 'string'|'number'|'boolean'|'array'|'object';
export interface ContractRule { path: string; required?: boolean; type?: ContractFieldType; values?: readonly (string | number | boolean)[]; min?: number; max?: number }
export interface EndpointContract { method: 'GET'|'POST'; path: string; operationId: string; response: string; roles: NexusRole[]|'authenticated'; requiredPermission: Permission; emits: string[]; audits: string[]; description: string; request?: string; responseEnvelope: 'ApiResponse'; pagination?: 'none'|'offset'|'cursor'; metadata: readonly ('requestId'|'timestamp'|'tenantId'|'racetrackId'|'organizationId'|'actorId'|'role'|'pagination')[] }
